 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { modelToRef } from '@kubevirt-ui/kubevirt-api/console';
 5	import { IoK8sApiNetworkingV1NetworkPolicy } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 6	import {
 7	  Breadcrumb,
 8	  BreadcrumbItem,
 9	  Flex,
10	  FlexItem,
11	  PageSection,
12	  PageSectionVariants,
13	  Stack,
14	  Title,
15	} from '@patternfly/react-core';
16	import { useLastNamespacePath } from '@utils/hooks/useLastNamespacePath';
17	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
18	import { getPolicyModel } from '@utils/resources/networkpolicies/utils';
19	import NetworkPolicyActions from '@views/networkpolicies/actions/NetworkPolicyActions';
20	
21	type NetworkAttachmentDefinitionPageTitleProps = {
22	  networkPolicy: IoK8sApiNetworkingV1NetworkPolicy;
23	};
24	
25	const NetworkAttachmentDefinitionPageTitle: FC<NetworkAttachmentDefinitionPageTitleProps> = ({
26	  networkPolicy,
27	}) => {
28	  const { t } = useNetworkingTranslation();
29	  const namespacePath = useLastNamespacePath();
30	
31	  const policyModel = getPolicyModel(networkPolicy);
32	
33	  return (
34	    <PageSection variant={PageSectionVariants.light}>
35	      <Breadcrumb>
36	        <BreadcrumbItem>
37	          <Link to={`/k8s/${namespacePath}/${modelToRef(policyModel)}`}>{policyModel.kind}</Link>
38	        </BreadcrumbItem>
39	        <BreadcrumbItem>{t('{{kind}} details', { kind: policyModel.kind })}</BreadcrumbItem>
40	      </Breadcrumb>
41	      <Stack hasGutter>
42	        <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
43	          <FlexItem>
44	            <Title headingLevel="h1">
45	              <span className="co-m-resource-icon co-m-resource-icon--lg">
46	                {t(policyModel.abbr)}
47	              </span>{' '}
48	              {networkPolicy?.metadata?.name}
49	            </Title>
50	          </FlexItem>
51	          <FlexItem>
52	            <NetworkPolicyActions obj={networkPolicy} />
53	          </FlexItem>
54	        </Flex>
55	      </Stack>
56	    </PageSection>
57	  );
58	};
59	
60	export default NetworkAttachmentDefinitionPageTitle;

